# add+modify_eas_records.hpp

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&records](auto&& conn) {
        for (const auto& record : records) {
          sqlgen::insert(conn, record).value();
        }
        return sqlgen::ok(conn);
      })
      .value();
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const T& new_value) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        std::string sql;

        // Determine the primary key column name based on table
        std::string pk_col;
        if (table_name == "Student") {
          pk_col = "SNo";
          sql = "UPDATE " + table_name + " SET " + col_name + " = ? WHERE " + pk_col + " = ?";
          return sqlgen::exec(conn, sql, new_value, record_id);
        } else if (table_name == "Course") {
          pk_col = "CID";
          sql = "UPDATE " + table_name + " SET " + col_name + " = ? WHERE " + pk_col + " = ?";
          return sqlgen::exec(conn, sql, new_value, std::stoi(record_id));
        } else if (table_name == "Score") {
          pk_col = "ScID";
          sql = "UPDATE " + table_name + " SET " + col_name + " = ? WHERE " + pk_col + " = ?";
          return sqlgen::exec(conn, sql, new_value, std::stoi(record_id));
        } else if (table_name == "Major") {
          pk_col = "MID";
          sql = "UPDATE " + table_name + " SET " + col_name + " = ? WHERE " + pk_col + " = ?";
          return sqlgen::exec(conn, sql, new_value, std::stoi(record_id));
        }

        return sqlgen::ok(conn);
      })
      .value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        if (table_name == "Student") {
          return sqlgen::remove<Student>(conn) | 
                 sqlgen::where("SNo = ?"_c, record_id);
        } else if (table_name == "Course") {
          return sqlgen::remove<Course>(conn) | 
                 sqlgen::where("CID = ?"_c, std::stoul(record_id));
        } else if (table_name == "Score") {
          return sqlgen::remove<Score>(conn) | 
                 sqlgen::where("ScID = ?"_c, std::stoul(record_id));
        } else if (table_name == "Major") {
          return sqlgen::remove<Major>(conn) | 
                 sqlgen::where("MID = ?"_c, std::stoul(record_id));
        }

        return sqlgen::ok(conn);
      })
      .value();
}
```

This implementation provides:

1. **`add_eas_records`**: A template function that connects to the database and inserts multiple records of type `T` into the specified table.

2. **`modify_eas_records_by_id`**: A template function that updates a specific column value for a record identified by its primary key. It handles different table types and their respective primary key columns.

3. **`delete_eas_records_by_id`**: Deletes a record from the specified table based on its primary key ID. It handles different primary key types (string for Student, uint32_t for others).

All functions follow the sqlgen chaining pattern with `.and_then()` and `.value()` for error handling.

