SQLGEN_DEFINE_TABLE(query_course_enrollment_stats::Course, course_id, title);
SQLGEN_DEFINE_TABLE(query_course_enrollment_stats::Enrollment, enrollment_id, course_id, grade);
SQLGEN_DEFINE_TABLE(query_course_enrollment_stats::CourseStatsView, title, student_count, avg_grade);

