 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  // Connect to SQLite database
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Create tables
  db.create_table<Course>();
  db.create_table<Enrollment>();

  // Build and execute query for enrollment statistics
  auto results = db.query<CourseStatsView>()
    .select(
      sqlgen::column<Course>("title"),
      sqlgen::count(sqlgen::column<Enrollment>("enrollment_id")).as("student_count"),
      sqlgen::avg(sqlgen::column<Enrollment>("grade")).as("avg_grade")
    )
    .from<Course>()
    .left_join<Enrollment>()
    .on(sqlgen::column<Course>("course_id") == sqlgen::column<Enrollment>("course_id"))
    .group_by(
      sqlgen::column<Course>("course_id"),
      sqlgen::column<Course>("title")
    )
    .execute();

  // Convert results to CourseStats vector
  std::vector<CourseStats> stats;
  stats.reserve(results.size());

  for (const auto& row : results) {
    stats.push_back({row.title, row.student_count, row.avg_grade});
  }

  return stats;
}

