    // Execute query and collect results
    std::vector<EmployeeManager> results;

    auto stmt = db.prepare(query);
    auto rows = stmt.execute();

    for (auto& row : rows) {
        EmployeeManager em;
        em.employee = row.template get<std::string>(0);
        em.manager = row.template get<std::optional<std::string>>(1);
        results.push_back(em);
    }

    return results;
