std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    // Open database connection
    auto db = sqlgen::sqlite::open("test_db.sqlite");

    // Start with base SELECT query
    auto query = sqlgen::select<Book>(db);

    // Add WHERE clauses dynamically based on provided filters

    // Filter by title using LIKE for partial matching
    if (filters.title_keyword.has_value()) {
        std::string pattern = "%" + filters.title_keyword.value() + "%";
        query = query.where([pattern](const Book& b) {
            return sqlgen::like(b.title, pattern);
        });
    }

    // Filter by minimum year using >= comparison
    if (filters.min_year.has_value()) {
        int min_year = filters.min_year.value();
        query = query.where([min_year](const Book& b) {
            return b.year >= min_year;
        });
    }

    // Filter by genre using exact match
    if (filters.genre.has_value()) {
        std::string genre_val = filters.genre.value();
        query = query.where([genre_val](const Book& b) {
            return b.genre == genre_val;
        });
    }

    // Filter by maximum price using <= comparison
    if (filters.max_price.has_value()) {
        double max_price = filters.max_price.value();
        query = query.where([max_price](const Book& b) {
            return b.price <= max_price;
        });
    }

    // Execute query and return results
