  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Connect to SQLite database
  sqlgen::sqlite::Connection db("test_db.sqlite");

  // SQLite doesn't natively support FULL OUTER JOIN
  // Simulate it using UNION of LEFT JOIN and RIGHT JOIN equivalent
  std::string query = R"(
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION ALL
    SELECT s.name as supplier_name, p.name as product_name
    FROM Product p
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )";

  std::vector<SupProd> results;

  // Prepare and execute the query
  auto stmt = db.prepare(query);

  // Iterate through results
  while (stmt.step()) {
    SupProd sp;

    // Get supplier name (handle potential NULL)
    if (stmt.is_null(0)) {
      sp.supplier_name = "";
    } else {
      sp.supplier_name = stmt.template column<std::string>(0);
    }

    // Get product name (optional)
    if (!stmt.is_null(1)) {
      sp.product_name = stmt.template column<std::string>(1);
    }

    results.push_back(sp);
  }

  return results;
}

}  // namespace full_join_suppliers_products
```

This implementation:

1. **Connects to the database**: Creates a connection to "test_db.sqlite"
2. **Simulates FULL JOIN**: Since SQLite doesn't support FULL OUTER JOIN natively, it uses:
   - LEFT JOIN from Supplier to get all suppliers with their products (or NULL)
   - UNION ALL with products that don't have matching suppliers
3. **Processes results**: Iterates through the result set and populates SupProd structs
4. **Handles NULL values**: Uses `std::optional` for product_name and empty string for NULL supplier_name
5. **Returns all rows**: Includes rows present in either table as required

