JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  // Create database connection
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Drop existing tables if they exist
  db.execute("DROP TABLE IF EXISTS Employee");
  db.execute("DROP TABLE IF EXISTS Department");

  // Create Department table
  db.execute(R"(
    CREATE TABLE Department (
      department_id INTEGER PRIMARY KEY,
      department_name TEXT NOT NULL,
      location TEXT
    )
  )");

  // Create Employee table
  db.execute(R"(
    CREATE TABLE Employee (
      employee_id INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name TEXT NOT NULL,
      last_name TEXT NOT NULL,
      salary REAL NOT NULL,
      FOREIGN KEY (department_id) REFERENCES Department(department_id)
    )
  )");

  // Insert departments
  auto dept_insert = db.prepare("INSERT INTO Department (department_id, department_name, location) VALUES (?, ?, ?)");
  for (const auto& dept : depts) {
    dept_insert.bind(1, dept.department_id.value);
    dept_insert.bind(2, dept.department_name);
    dept_insert.bind(3, dept.location);
    dept_insert.execute();
    dept_insert.reset();
  }

  // Insert employees
  auto emp_insert = db.prepare("INSERT INTO Employee (employee_id, department_id, first_name, last_name, salary) VALUES (?, ?, ?, ?, ?)");
  for (const auto& emp : emps) {
    emp_insert.bind(1, emp.employee_id.value);
    emp_insert.bind(2, emp.department_id);
    emp_insert.bind(3, emp.first_name);
    emp_insert.bind(4, emp.last_name);
    emp_insert.bind(5, emp.salary);
    emp_insert.execute();
    emp_insert.reset();
  }

  JoinAnalysis analysis;

  // INNER JOIN: employees with assigned departments
  {
    auto stmt = db.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      INNER JOIN Employee e ON d.department_id = e.department_id
    )");

    while (stmt.step()) {
      JoinResult jr;
      jr.department_name = stmt.get_text(0);
      jr.first_name = stmt.get_text(1);
      jr.last_name = stmt.get_text(2);
      jr.salary = stmt.get_double(3);
      analysis.inner_join_results.push_back(jr);
    }
  }

  // LEFT JOIN: all employees (even without departments)
  {
    auto stmt = db.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Employee e
      LEFT JOIN Department d ON e.department_id = d.department_id
    )");

    while (stmt.step()) {
      JoinResult jr;
      if (stmt.column_type(0) != SQLITE_NULL) {
        jr.department_name = stmt.get_text(0);
      }
      if (stmt.column_type(1) != SQLITE_NULL) {
        jr.first_name = stmt.get_text(1);
      }
      if (stmt.column_type(2) != SQLITE_NULL) {
        jr.last_name = stmt.get_text(2);
      }
      if (stmt.column_type(3) != SQLITE_NULL) {
        jr.salary = stmt.get_double(3);
      }
      analysis.left_join_results.push_back(jr);
    }
  }

  // RIGHT JOIN: all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN, so we simulate with LEFT JOIN
  {
    auto stmt = db.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      LEFT JOIN Employee e ON d.department_id = e.department_id
    )");

    while (stmt.step()) {
      JoinResult jr;
      if (stmt.column_type(0) != SQLITE_NULL) {
        jr.department_name = stmt.get_text(0);
      }
      if (stmt.column_type(1) != SQLITE_NULL) {
        jr.first_name = stmt.get_text(1);
      }
      if (stmt.column_type(2) != SQLITE_NULL) {
        jr.last_name = stmt.get_text(2);
      }
      if (stmt.column_type(3) != SQLITE_NULL) {
        jr.salary = stmt.get_double(3);
      }
      analysis.right_join_results.push_back(jr);
    }
  }

  // FULL JOIN: all employees and departments
  // SQLite doesn't support FULL OUTER JOIN, so we use UNION
  {
    auto stmt = db.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Employee e
      LEFT JOIN Department d ON e.department_id = d.department_id
      UNION
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      LEFT JOIN Employee e ON d.department_id = e.department_id
      WHERE e.employee_id IS NULL
    )");

    while (stmt.step()) {
      JoinResult jr;
      if (stmt.column_type(0) != SQLITE_NULL) {
        jr.department_name = stmt.get_text(0);
      }
      if (stmt.column_type(1) != SQLITE_NULL) {
        jr.first_name = stmt.get_text(1);
      }
      if (stmt.column_type(2) != SQLITE_NULL) {
        jr.last_name = stmt.get_text(2);
      }
      if (stmt.column_type(3) != SQLITE_NULL) {
        jr.salary = stmt.get_double(3);
      }
      analysis.full_join_results.push_back(jr);
    }
  }

  return analysis;
}

}  // namespace analyze_department_employees
